import requests
import json

# --- Configuration ---
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 15672
RABBITMQ_API_USER = 'your_admin_user' # User with administrator privileges
RABBITMQ_API_PASS = 'your_admin_password' # Password for the admin user

# Define vhosts, users, and their permissions
# Each entry in the list represents an application/tenant
# 'vhost_name': The name of the virtual host
# 'username': The user for this vhost
# 'password': The password for this user
# 'configure_regex': Regex for configure permissions (e.g., '^$')
# 'write_regex': Regex for write permissions (e.g., '^app_queue.*')
# 'read_regex': Regex for read permissions (e.g., '^app_queue.*')
CONFIG = [
    {
        'vhost_name': 'app_tenant_A',
        'username': 'user_A',
        'password': 'password_A',
        'configure_regex': '^$',  # Can configure nothing (exchanges, queues, bindings)
        'write_regex': '^app_A_queue.*', # Can write to queues starting with 'app_A_queue'
        'read_regex': '^app_A_queue.*',  # Can read from queues starting with 'app_A_queue'
    },
    {
        'vhost_name': 'app_tenant_B',
        'username': 'user_B',
        'password': 'password_B',
        'configure_regex': '^$',
        'write_regex': '^app_B_queue.*',
        'read_regex': '^app_B_queue.*',
    },
    {
        'vhost_name': 'shared_service_vhost',
        'username': 'shared_user',
        'password': 'shared_password',
        'configure_regex': '^$', # No configure permissions
        'write_regex': '^shared_queue.*',
        'read_regex': '^shared_queue.*',
    }
]

# --- RabbitMQ API Base URL ---
API_BASE_URL = f'http://{RABBITMQ_HOST}:{RABBITMQ_PORT}/api'

# --- Helper function for API requests ---
def make_api_request(method, endpoint, data=None, expected_status=(200, 201, 204)):
    url = f'{API_BASE_URL}/{endpoint}'
    headers = {'Content-Type': 'application/json'}
    auth = (RABBITMQ_API_USER, RABBITMQ_API_PASS)

    try:
        if method == 'GET':
            response = requests.get(url, auth=auth, headers=headers)
        elif method == 'PUT':
            response = requests.put(url, auth=auth, headers=headers, data=json.dumps(data))
        elif method == 'POST':
            response = requests.post(url, auth=auth, headers=headers, data=json.dumps(data))
        elif method == 'DELETE':
            response = requests.delete(url, auth=auth, headers=headers)
        else:
            raise ValueError(f"Unsupported HTTP method: {method}")

        if response.status_code not in expected_status:
            print(f"Error {method} {url}: {response.status_code} - {response.text}")
            response.raise_for_status() # Raise an exception for bad status codes
        return response
    except requests.exceptions.ConnectionError:
        print(f"Connection Error: Could not connect to RabbitMQ Management API at {url}")
        print("Please ensure RabbitMQ is running and the management plugin is enabled.")
        exit(1)
    except requests.exceptions.RequestException as e:
        print(f"Request Error: {e}")
        exit(1)

# --- Main Script Logic ---
def configure_rabbitmq():
    print(f"Connecting to RabbitMQ Management API at {API_BASE_URL}")

    for item in CONFIG:
        vhost_name = item['vhost_name']
        username = item['username']
        password = item['password']
        configure_regex = item['configure_regex']
        write_regex = item['write_regex']
        read_regex = item['read_regex']

        # 1. Create Virtual Host
        print(f"\n--- Processing '{vhost_name}' ---")
        print(f"Creating vhost: {vhost_name}")
        make_api_request('PUT', f'vhosts/{vhost_name}', expected_status=(201, 204)) # 201 Created, 204 No Content if already exists
        print(f"Vhost '{vhost_name}' ensured.")

        # 2. Create User
        print(f"Creating user: {username}")
        user_data = {
            'password': password,
            'tags': 'management' # Optional: Add 'management' tag if user needs UI access
        }
        make_api_request('PUT', f'users/{username}', data=user_data, expected_status=(201, 204))
        print(f"User '{username}' ensured.")

        # 3. Set Permissions for User on Vhost
        print(f"Setting permissions for user '{username}' on vhost '{vhost_name}'")
        permissions_data = {
            'configure': configure_regex,
            'write': write_regex,
            'read': read_regex
        }
        make_api_request('PUT', f'permissions/{vhost_name}/{username}', data=permissions_data, expected_status=(201, 204))
        print(f"Permissions for '{username}' on '{vhost_name}' set.")

    print("\n--- Configuration Complete ---")
    print("Please verify the setup in the RabbitMQ Management UI.")

if __name__ == '__main__':
    configure_rabbitmq()